import React from 'react';
import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';

import MasterLayout from './layouts/admin/MasterLayout';
import Home from './components/frontend/Home';
import Login from './layouts/frontend/auth/login';
import Register from './layouts/frontend/auth/register';
import axios from 'axios';
import 'bootstrap/dist/css/bootstrap.min.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

// Axios configuration
axios.defaults.baseURL = 'http://127.0.0.1:8000';
axios.defaults.headers.post['Content-Type'] = 'application/json';
axios.defaults.headers.post['Accept'] = 'application/json';
axios.defaults.withCredentials = true;

// Add request interceptor to include auth token
axios.interceptors.request.use(
  (config) =>
  {
    const token = localStorage.getItem('auth_token');
    if (token)
    {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) =>
  {
    return Promise.reject(error);
  }
);

// Add response interceptor to handle token expiration
axios.interceptors.response.use(
  (response) => response,
  (error) =>
  {
    if (error.response?.status === 401)
    {
      // Token expired or invalid
      localStorage.removeItem('auth_token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

function App()
{
  const isAuthenticated = localStorage.getItem('auth_token');

  return (
    <div className="App">
      <Router>
        <Routes>
          <Route path="/" element={<Navigate replace to="/admin/dashboard" />} />
          {/* Public and Authentication Routes */}
          <Route path="/register" element={isAuthenticated ? <Navigate replace to="/" /> : <Register />} />
          <Route path="/login" element={isAuthenticated ? <Navigate replace to="/" /> : <Login />} />
          <Route path="/home" element={<Home />} />
          <Route path="/login">
            {localStorage.getItem('auth_token') ? <Navigate replace to="/" /> : <Login />}
          </Route>
          <Route path="admin">
            {localStorage.getItem('auth_token') ? <MasterLayout /> : <Navigate replace to="/" />}
          </Route>
          <Route path="/admin/*" element={<MasterLayout />} />

          {/* Protected Admin Route */}
          <Route path="/admin/*" element={isAuthenticated ? <MasterLayout /> : <Navigate replace to="/login" />} />
          <Route path="/" element={<Navigate replace to="/admin/dashboard" />} />
        </Routes>
      </Router>
    </div>
  );
}

export default App;
